class Queue:
    def __init__(self):
        self._data = []
    def enqueue(self, item):
        self._data.append(item)
    def dequeue(self):
        return self._data.pop(0)
    def __len__(self):
        return len(self._data)
q = Queue()
q.enqueue(1)
q.enqueue(2)
q.enqueue(3)
assert q.dequeue() == 1
assert q.dequeue() == 2
assert len(q) == 1
